import{_ as t,c as i,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Avancé : Pipeline et mécanismes internes | Tutoriel AI App Factory","description":"Découvrez en profondeur le pipeline en 7 étapes de l'AI App Factory, le planificateur Sisyphus, les mécanismes de sécurité et les stratégies de gestion des échecs. Maîtrisez l'optimisation du contexte et les techniques de configuration avancée.","frontmatter":{"title":"Avancé : Pipeline et mécanismes internes | Tutoriel AI App Factory","sidebarTitle":"Avancé : Pipeline","subtitle":"Avancé : Pipeline et mécanismes internes","description":"Découvrez en profondeur le pipeline en 7 étapes de l'AI App Factory, le planificateur Sisyphus, les mécanismes de sécurité et les stratégies de gestion des échecs. Maîtrisez l'optimisation du contexte et les techniques de configuration avancée.","tags":["Pipeline","Planificateur","Sécurité des permissions","Gestion des échecs"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"fr/hyz1992/agent-app-factory/advanced/index.md","filePath":"fr/hyz1992/agent-app-factory/advanced/index.md"}`),n={name:"fr/hyz1992/agent-app-factory/advanced/index.md"};function r(l,e,o,c,p,d){return s(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="avance-pipeline-et-mecanismes-internes" tabindex="-1">Avancé : Pipeline et mécanismes internes <a class="header-anchor" href="#avance-pipeline-et-mecanismes-internes" aria-label="Permalink to &quot;Avancé : Pipeline et mécanismes internes&quot;">​</a></h1><p>Ce chapitre explique en détail les mécanismes de base et les fonctionnalités avancées de l&#39;AI App Factory, notamment le fonctionnement détaillé du pipeline en 7 étapes, les stratégies de planification du planificateur Sisyphus, les mécanismes de permissions et de sécurité, les stratégies de gestion des échecs, ainsi que l&#39;optimisation du contexte pour économiser les coûts en tokens.</p><div class="warning custom-block"><p class="custom-block-title">Prérequis</p><p>Avant d&#39;étudier ce chapitre, assurez-vous d&#39;avoir terminé :</p><ul><li><a href="./../../start/getting-started/">Démarrage rapide</a> et <a href="./../../start/installation/">Installation et configuration</a></li><li><a href="./../../start/pipeline-overview/">Vue d&#39;ensemble du pipeline en 7 étapes</a></li><li><a href="./../../platforms/claude-code/">Intégration de plateforme</a> configuration</li></ul></div><h2 id="contenu-du-chapitre" tabindex="-1">Contenu du chapitre <a class="header-anchor" href="#contenu-du-chapitre" aria-label="Permalink to &quot;Contenu du chapitre&quot;">​</a></h2><p>Ce chapitre couvre les sujets suivants :</p><h3 id="explication-detaillee-du-pipeline-en-7-etapes" tabindex="-1">Explication détaillée du pipeline en 7 étapes <a class="header-anchor" href="#explication-detaillee-du-pipeline-en-7-etapes" aria-label="Permalink to &quot;Explication détaillée du pipeline en 7 étapes&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">Étape 1 : Bootstrap - Structurez l&#39;idée produit</a></strong></p><ul><li>Apprenez à transformer une idée produit floue en document structuré</li><li>Comprenez les formats d&#39;entrée et de sortie du Bootstrap Agent</li></ul></li><li><p><strong><a href="./stage-prd/">Étape 2 : PRD - Générez le document de spécifications produit</a></strong></p><ul><li>Générez un PRD de niveau MVP, incluant les user stories, la liste des fonctionnalités et les non-objectifs</li><li>Maîtrisez les techniques de décomposition des exigences et de priorisation</li></ul></li><li><p><strong><a href="./stage-ui/">Étape 3 : UI - Concevez l&#39;interface et le prototype</a></strong></p><ul><li>Utilisez la compétence ui-ux-pro-max pour concevoir la structure UI et le prototype prévisualisable</li><li>Comprenez le processus de conception d&#39;interface et les meilleures pratiques</li></ul></li><li><p><strong><a href="./stage-tech/">Étape 4 : Tech - Concevez l&#39;architecture technique</a></strong></p><ul><li>Concevez l&#39;architecture technique minimale viable et le modèle de données Prisma</li><li>Maîtrisez les principes de sélection technologique et de conception architecturale</li></ul></li><li><p><strong><a href="./stage-code/">Étape 5 : Code - Générez du code exécutable</a></strong></p><ul><li>Générez le code frontend et backend, les tests et la configuration à partir du schéma UI et de la conception Tech</li><li>Comprenez le processus de génération de code et le système de templates</li></ul></li><li><p><strong><a href="./stage-validation/">Étape 6 : Validation - Validez la qualité du code</a></strong></p><ul><li>Validez l&#39;installation des dépendances, la vérification des types, le schéma Prisma et la qualité du code</li><li>Maîtrisez le processus automatisé de vérification de qualité</li></ul></li><li><p><strong><a href="./stage-preview/">Étape 7 : Preview - Générez le guide de déploiement</a></strong></p><ul><li>Générez la documentation complète des instructions d&#39;exécution et la configuration de déploiement</li><li>Apprenez l&#39;intégration CI/CD et la configuration des Git Hooks</li></ul></li></ul><h3 id="mecanismes-internes" tabindex="-1">Mécanismes internes <a class="header-anchor" href="#mecanismes-internes" aria-label="Permalink to &quot;Mécanismes internes&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Explication détaillée du planificateur Sisyphus</a></strong></p><ul><li>Comprenez comment le planificateur coordonne le pipeline, gère les états et effectue les vérifications de permissions</li><li>Maîtrisez les stratégies de planification et les principes de la machine à états</li></ul></li><li><p><strong><a href="./context-optimization/">Optimisation du contexte : Exécution par sessions</a></strong></p><ul><li>Apprenez à utiliser la commande <code>factory continue</code> pour économiser des tokens</li><li>Maîtrisez les meilleures pratiques pour créer de nouvelles sessions à chaque étape</li></ul></li><li><p><strong><a href="./security-permissions/">Mécanismes de permissions et de sécurité</a></strong></p><ul><li>Comprenez la matrice des limites de capacités, le traitement des dépassements de permissions et les mécanismes de vérification de sécurité</li><li>Maîtrisez la configuration de sécurité et la gestion des permissions</li></ul></li><li><p><strong><a href="./failure-handling/">Gestion des échecs et rollback</a></strong></p><ul><li>Apprenez l&#39;identification des échecs, les mécanismes de réessai, les stratégies de rollback et les processus d&#39;intervention humaine</li><li>Maîtrisez les techniques de dépannage et de récupération</li></ul></li></ul><h2 id="recommandations-pour-le-parcours-d-apprentissage" tabindex="-1">Recommandations pour le parcours d&#39;apprentissage <a class="header-anchor" href="#recommandations-pour-le-parcours-d-apprentissage" aria-label="Permalink to &quot;Recommandations pour le parcours d&#39;apprentissage&quot;">​</a></h2><h3 id="ordre-d-apprentissage-recommande" tabindex="-1">Ordre d&#39;apprentissage recommandé <a class="header-anchor" href="#ordre-d-apprentissage-recommande" aria-label="Permalink to &quot;Ordre d&#39;apprentissage recommandé&quot;">​</a></h3><ol><li><p><strong>Complétez d&#39;abord le pipeline en 7 étapes</strong> (dans l&#39;ordre)</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>Chaque étape a des entrées et sorties claires, les étudier dans l&#39;ordre permet d&#39;établir une compréhension complète</li></ul></li><li><p><strong>Ensuite, étudiez le planificateur et l&#39;optimisation du contexte</strong></p><ul><li>Comprenez comment Sisyphus coordonne ces 7 étapes</li><li>Apprenez à optimiser le contexte pour économiser les coûts en tokens</li></ul></li><li><p><strong>Enfin, étudiez la sécurité et la gestion des échecs</strong></p><ul><li>Maîtrisez les limites de permissions et les mécanismes de sécurité</li><li>Comprenez les scénarios d&#39;échec et les stratégies de réponse</li></ul></li></ol><h3 id="points-d-accentuation-selon-les-roles" tabindex="-1">Points d&#39;accentuation selon les rôles <a class="header-anchor" href="#points-d-accentuation-selon-les-roles" aria-label="Permalink to &quot;Points d&#39;accentuation selon les rôles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rôle</th><th>Chapitres prioritaires</th></tr></thead><tbody><tr><td><strong>Développeur</strong></td><td>Code, Validation, Tech, Orchestrateur</td></tr><tr><td><strong>Chef de produit</strong></td><td>Bootstrap, PRD, UI, Preview</td></tr><tr><td><strong>Lead technique</strong></td><td>Tech, Code, Sécurité, Gestion des échecs</td></tr><tr><td><strong>Ingénieur DevOps</strong></td><td>Validation, Preview, Optimisation du contexte</td></tr></tbody></table><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, vous pouvez continuer à apprendre :</p><ul><li><strong><a href="./../../faq/troubleshooting/">FAQ et dépannage</a></strong> - Résolvez les problèmes rencontrés lors de l&#39;utilisation</li><li><strong><a href="./../../faq/best-practices/">Meilleures pratiques</a></strong> - Maîtrisez les techniques pour utiliser efficacement la Factory</li><li><strong><a href="./../../appendix/cli-commands/">Référence des commandes CLI</a></strong> - Consultez la liste complète des commandes</li><li><strong><a href="./../../appendix/code-standards/">Normes de code</a></strong> - Découvrez les normes que le code généré doit respecter</li></ul><hr><p>💡 <strong>Conseil</strong> : Si vous rencontrez des problèmes lors de l&#39;utilisation, consultez d&#39;abord le chapitre <a href="./../../faq/troubleshooting/">FAQ et dépannage</a>.</p>',19)])])}const h=t(n,[["render",r]]);export{m as __pageData,h as default};
